function statusBadgeClass(s) {
  if (!s) return 'b-default';
  var v = (s || '').toLowerCase();
  if (v === 'received' || v === 'active') return 'b-received';
  if (v === 'sold') return 'b-sold';
  if (v === 'repair') return 'b-repair';
  return 'b-default';
}
function render(model) {
  var ref = document.getElementById('asset_ref');
  var cust = document.getElementById('customer_name');
  var col = document.getElementById('collection_id');
  var type = document.getElementById('item_type');
  var badge = document.getElementById('status_badge');
  if (ref) ref.textContent = model.asset_ref || '—';
  if (cust) cust.textContent = model.customer_name || '—';
  if (col) col.textContent = model.collection_id ? 'Collection ' + model.collection_id : '—';
  if (type) type.textContent = model.item_type || '—';
  if (badge) {
    badge.textContent = model.status || '—';
    badge.className = 'badge ' + statusBadgeClass(model.status);
  }
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

